{"type":"user","message":{"role":"user","content":[{"tool_use_id":"tooluse_wx3ShsqoveLcF3jHTxsgMc","type":"tool_result","content":"The file /Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_37_floor_ceiling_reversal/revised/claudecode/floor_ceiling_analysis.py has been updated successfully."}]},"parent_tool_use_id":null,"session_id":"2d37f2a7-f681-4cce-abd1-1da066f791f2","uuid":"f0874945-e3a0-4a03-b1c1-ee24fffbced1","timestamp":"2026-04-16T12:37:21.626Z","tool_use_result":{"filePath":"/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_37_floor_ceiling_reversal/revised/claudecode/floor_ceiling_analysis.py","oldString":"            f.write(f\"{r['stock_code']},{r['limit_down_date']},{r['limit_up_date']},{r['drawdown_pct']}\\n')","newString":"            f.write(f\"{r['stock_code']},{r['limit_down_date']},{r['limit_up_date']},{r['drawdown_pct']}\\n\")","originalFile":"#!/usr/bin/env python3\n\"\"\"\n地天板极端反转形态识别\n识别创业板中的\"地天板\"形态（跌停后打开再涨停）\n\"\"\"\n\nimport sys\nsys.path.insert(0, '/Users/tomato/Documents/potato/project/YFD')\n\nimport pandas as pd\nfrom datetime import datetime, timedelta\nfrom data_source import DataSource\n\ndef identify_floor_ceiling_patterns():\n    \"\"\"识别地天板形态\"\"\"\n\n    ds = DataSource()\n\n    # 设置日期范围：截至2024-09-23的最近20个交易日\n    end_date = '2024-09-23'\n    start_date = '2024-08-20'  # 大约20个交易日前\n\n    # 获取创业板股票列表（300开头）\n    stock_list = ds.stock_basic()\n    chinext_stocks = stock_list[stock_list['ts_code'].str.startswith('300')]['ts_code'].tolist()\n\n    results = []\n\n    for stock_code in chinext_stocks:\n        try:\n            # 获取股票基本信息\n            stock_info = stock_list[stock_list['ts_code'] == stock_code].iloc[0]\n            stock_name = stock_info['name']\n            list_date = stock_info['list_date']\n\n            # 排除ST股票\n            if 'ST' in stock_name:\n                continue\n\n            # 排除次新股（上市不足60个交易日）\n            list_date_dt = datetime.strptime(list_date, '%Y%m%d')\n            end_date_dt = datetime.strptime(end_date, '%Y-%m-%d')\n            days_since_listing = (end_date_dt - list_date_dt).days\n            if days_since_listing < 90:  # 约60个交易日\n                continue\n\n            # 获取日线数据\n            df = ds.daily(ts_code=stock_code, start_date=start_date.replace('-', ''),\n                         end_date=end_date.replace('-', ''))\n\n            if df is None or len(df) < 2:\n                continue\n\n            df = df.sort_values('trade_date')\n            df['trade_date'] = pd.to_datetime(df['trade_date'])\n\n            # 计算振幅\n            df['amplitude'] = ((df['high'] - df['low']) / df['pre_close'] * 100).abs()\n\n            # 识别跌停日\n            for i in range(len(df) - 1):\n                row = df.iloc[i]\n                pct_chg = row['pct_chg']\n                amplitude = row['amplitude']\n\n                # 判断是否跌停（创业板：-20%或-10%）\n                is_limit_down = (pct_chg <= -19.5 or (pct_chg <= -9.5 and pct_chg > -11))\n\n                # 判断跌停是否被打开（振幅>3%，非一字板）\n                is_opened = amplitude > 3.0\n\n                if not (is_limit_down and is_opened):\n                    continue\n\n                limit_down_date = row['trade_date']\n\n                # 检查当日或次日是否涨停\n                for j in range(i, min(i + 2, len(df))):\n                    check_row = df.iloc[j]\n                    check_pct = check_row['pct_chg']\n\n                    # 判断是否涨停（创业板：20%或10%）\n                    is_limit_up = (check_pct >= 19.5 or (check_pct >= 9.5 and check_pct < 11))\n\n                    if not is_limit_up:\n                        continue\n\n                    limit_up_date = check_row['trade_date']\n                    limit_up_low = check_row['low']\n\n                    # 检查封板强度（使用尾盘成交量占比作为代理）\n                    # 这里简化处理，假设强封板\n\n                    # 检查涨停后5日内最低价不跌破涨停日最低价\n                    future_5_days = df.iloc[j+1:min(j+6, len(df))]\n\n                    if len(future_5_days) < 5:\n                        continue  # 数据不足5天\n\n                    min_low_after = future_5_days['low'].min()\n\n                    if min_low_after >= limit_up_low:\n                        # 计算涨停后5日最低回撤\n                        limit_up_close = check_row['close']\n                        drawdown = ((min_low_after - limit_up_close) / limit_up_close * 100)\n\n                        results.append({\n                            'stock_code': stock_code,\n                            'limit_down_date': limit_down_date.strftime('%Y-%m-%d'),\n                            'limit_up_date': limit_up_date.strftime('%Y-%m-%d'),\n                            'drawdown_pct': round(drawdown, 2)\n                        })\n                        break\n\n        except Exception as e:\n            continue\n\n    return results\n\ndef main():\n    \"\"\"主函数\"\"\"\n    print(\"开始识别地天板形态...\")\n\n    results = identify_floor_ceiling_patterns()\n\n    # 写入结果文件\n    output_file = '/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_37_floor_ceiling_reversal/revised/claudecode/floor_ceiling.txt'\n\n    with open(output_file, 'w', encoding='utf-8') as f:\n        f.write('股票代码,跌停日期,涨停日期,涨停后5日最低回撤(%)\\n')\n\n        if len(results) == 0:\n            f.write('# 无符合条件的地天板形态\\n')\n        else:\n            for r in results:\n                f.write(f\"{r['stock_code']},{r['limit_down_date']},{r['limit_up_date']},{r['drawdown_pct']}\\n')\n\n    print(f\"分析完成，找到 {len(results)} 个符合条件的地天板形态\")\n    print(f\"结果已写入: {output_file}\")\n\n    return results\n\nif __name__ == '__main__':\n    main()\n","structuredPatch":[{"oldStart":133,"oldLines":7,"newStart":133,"newLines":7,"lines":["             f.write('# 无符合条件的地天板形态\\n')","         else:","             for r in results:","-                f.write(f\"{r['stock_code']},{r['limit_down_date']},{r['limit_up_date']},{r['drawdown_pct']}\\n')","+                f.write(f\"{r['stock_code']},{r['limit_down_date']},{r['limit_up_date']},{r['drawdown_pct']}\\n\")"," ","     print(f\"分析完成，找到 {len(results)} 个符合条件的地天板形态\")","     print(f\"结果已写入: {output_file}\")"]}],"userModified":false,"replaceAll":false}}
